function SignalListener (owner, fn, ctx, once) {
  this.fn = fn
  this.ctx = ctx || null
  this.owner = owner
  this.once = !!once
}

function removeNode (owner, node) {
  if (node.prev) node.prev.next = node.next
  if (node.next) node.next.prev = node.prev
  node.ctx = node.fn = node.owner = null
  if (node === owner._first) owner._first = node.next
  if (node === owner._last) owner._last = node.prev
}

let batchDepth = 0
const batchQueue = new Map()

class Signal {
  constructor () {
    this._first = this._last = null
    this._symbol = Symbol.for('signal')
  }

  dispatch (...values) {
    if (batchDepth > 0) {
      batchQueue.set(this, values)
      return
    }

    let node = this._first
    while (node) {
      node.fn.call(node.ctx, ...values)
      node.once && this.unsubscribe(node)
      node = node.next
    }
  }

  subscribe (fn, ctx, once) {
    const node = new SignalListener(this, fn, ctx, once)
    if (!this._first) {
      this._first = node
      this._last = node
    } else {
      this._last.next = node
      node.prev = this._last
      this._last = node
    }
    return node
  }

  subscribeOnce (fn, ctx) {
    return this.subscribe(fn, ctx, true)
  }

  unsubscribe (fn, ctx) {
    if (!fn) throw new Error('unsubscribe() called without a handler')
    if (fn instanceof SignalListener) return removeNode(this, fn)
    if (!ctx) ctx = null
    let node = this._first
    while (node) {
      if (node.fn === fn && node.ctx === ctx) removeNode(this, node)
      node = node.next
    }
  }

  unsubscribeAll () {
    let node = this._first
    this._first = this._last = null
    while (node) {
      removeNode(this, node)
      node = node.next
    }
  }
}

export function batch (fn) {
  batchDepth++
  try {
    fn()
  } finally {
    batchDepth--
    if (batchDepth === 0) {
      const queue = [...batchQueue]
      batchQueue.clear()
      for (const [signal, values] of queue) signal.dispatch(...values)
    }
  }
}

export { Signal }
export default function signal () {
  return new Signal()
}
